#include<cstdio>
#include<vector>
#include<queue>
#include<cstring>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
#define getchar() (p1==p2&&(p2=(p1=buf)+fread(buf,1,1<<19,stdin),p1==p2)?EOF:*p1++)
#define putchar(a) (*O++=(a))
char buf[1<<23],*p1=buf,*p2=buf,obuf[1<<23],*O=obuf;
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void pt(const int &p){if(p>9)pt(p/10);putchar(p%10+'0');}
inline void print(const int &p,const char &ch){pt(p<0?putchar('-'),-p:p);putchar(ch);}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
const int N=1e4+10,M=1e5+10;int n,m,deg[N],vis[N];std::vector<int> G[N],ans1,ans2;std::queue<int> q[N];
inline void Solve()
{
	n=read();m=read();rep(0,n,i){G[i].clear();while(!q[i].empty())q[i].pop();}
	rep(1,m,i){int x=read(),y=read();G[x].push_back(y);G[y].push_back(x);++deg[x];++deg[y];}
	int mn=0x3f3f3f3f;rep(1,n,i)q[deg[i]].push(i),mn=min(mn,deg[i]);
	int mx=0,idx=0,cnt=0;while(mn<n)
	{
		while(!q[mn].empty()&&vis[q[mn].front()])q[mn].pop();if(q[mn].empty()){++mn;continue;}
		if(mn>mx)mx=mn,idx=cnt;int x=q[mn].front();q[mn].pop();vis[x]=++cnt;ans2.push_back(x);
		for(int u: G[x])if(!vis[u]){vis[u]=cnt;for(int v: G[u])q[--deg[v]].push(v),mn=min(mn,deg[v]);}
	}
	rep(1,n,i)if(vis[i]>=idx)ans1.push_back(i);
	print(ans1.size(),' ');for(int v: ans1)print(v,' ');putchar('\n');
	print(ans2.size(),' ');for(int v: ans2)print(v,' ');putchar('\n');
	ans1.clear();ans2.clear();memset(deg,0,sizeof(deg));memset(vis,0,sizeof(vis));
}
int main()
{
	int T=read();while(T--)Solve();
	fwrite(obuf,O-obuf,1,stdout);return 0;
}
